import { Grid, useGrid } from "@ace-grid/enterprise";
import "@ace-grid/enterprise/styles.css";

export function RevenueGridWithActions() {
  const [rows, api] = useGrid({
    columns,
    initialRows: seedRows,
    sortMode: "client",
  });

  const gridProps = {
    data: {
      rows,
      columns,
    },
    layout: {
      width: 960,
      height: 420,
    },
  };

  return (
    <>
      <button
        type="button"
        onClick={() =>
          api.appendRow({
            data: {
              make: { value: "Tesla" },
              status: { value: "Draft" },
            },
          })
        }
      >
        Add row
      </button>

      <Grid {...gridProps} />
    </>
  );
}

