import { Component, ViewChild } from "@angular/core";
import { AceGridComponent } from "@ace-grid/angular";

@Component({
  selector: "app-revenue-grid",
  template: `
    <button type="button" (click)="addRow()">Add row</button>
    <ace-grid-angular #grid [props]="gridProps" />
  `,
})
export class RevenueGridComponent {
  @ViewChild("grid") grid?: AceGridComponent;
  gridProps = {
    data: {
      rows,
      columns,
    },
    layout: {
      width: 960,
      height: 420,
    },
  };

  addRow() {
    this.grid?.getActions()?.appendRow({
      data: {
        make: { value: "Tesla" },
        status: { value: "Draft" },
      },
    });
  }
}

